                                        <Input
                                          type="number"
                                          step="0.01"
                                          min="0"
                                          value={customWeights[crit.id] || ""}
                                          onChange={(e) => setCustomWeights({
                                            ...customWeights,
                                            [crit.id]: e.target.value,
                                          })}
                                          onKeyDown={handleKeyDown}
                                          className="w-24 h-7 text-xs text-center"
                                          placeholder="0.00"
                                        />
