                                          fontSize: "10px",
                                          color: "#000",
                                          fontWeight: 700,
                                          backgroundColor: "rgba(255, 255, 255, 0.95)",
                                          border: "1px solid #000",
                                          padding: "4px 8px",
                                          top: 70,
                                          left: "50%",
