                                              fontSize: "10px",
                                              color: "#000",
                                              fontWeight: 700,
                                              backgroundColor: "rgba(255, 255, 255, 0.95)",
                                              border: "1px solid #000",
                                              padding: "4px 8px",
                                              top: 50,
                                              left: "50%",
                                              transform: "translateX(-50%)",
                                              width: "max-content",
                                              maxWidth: "95%",
                                              zIndex: 50,
                                              boxShadow: "2px 2px 0px rgba(0,0,0,1)",
