                      setAhpCalculatedWeights(weights)
                      setIsAhpDialogOpen(false)

                      // Update criteria with new weights
                      const updatedCriteria = criteria.map(c => ({
                        ...c,
                        weight: weights[c.id] || 0
                      }))
                      setCriteria(updatedCriteria)
                      setWeightMethod("ahp")

